                // Ozean, leicht teurer fГјr See/Fluss вҶ’ einmal pro Sample-
                // Zelle, nicht pro Blade (16Г—16=256 Samples pro Chunk).
                const waterY = this._waterLevelAt(baseX, baseZ);
