// N3 (Naht В§12) вҖ” die LOD-Hysterese: ein bestehender Chunk wechselt seine LOD
// erst, wenn r die Band-Grenze um diese Ring-Zahl KLAR Гјberschreitet (Deadband
// gegen Flip-Flop-Pop am Grat). Asymmetrisch (in `_voxelChunkLodFor`): VERFEINERN
// sofort (Detail soll prompt erscheinen), VERGRГ–BERN nur im klaren Гңberschritt.
AnazhRealm.LOD_HYSTERESIS_RINGS = 1;

// V17.33 Phase A (DSL-Weltregeln) вҖ” die Stellschrauben des stehenden Regel-Satzes.
// EIN frozen Objekt (kein per-Frame-Getter вҖ” _tickWorldRules liest es jeden Frame):
//   cap            вҖ” max stehende Regeln (Runaway-Schutz; VerdrГӨngung in _evictWorldRule)
//   budgetPerFrame вҖ” max Regel-EFFEKTE pro Frame (die 119 FPS bleiben heilig)
//   defaultEverySecвҖ” Default-Feuer-Intervall einer Regel
//   minEverySec    вҖ” Floor вҶ’ verhindert Per-Frame-Feuern (Performance + Determinismus)
// V17.35 Phase C вҖ” der Nexus EVOLVIERT Regeln: zusГӨtzliche Stellschrauben fГјr
// Komposition (composeRuleProb/ruleEverySec*/ruleTtl*) + die per-Regel-Fitness
// Гјber ein Lebens-Fenster (costBudgetMs/renewFitness/mutateSurvivorProb). Eine
// Nexus-Regel ist EPHEMER (ttlSec) вҖ” am Lebens-Ende bewertet: gut вҶ’ erneuern,
// schlecht/inert вҶ’ verfallen. So lernt die Welt ihre eigene Logik (Selektion).
// V18.112 вҖ” E4-KRISTALL + E5 (die benannte Folge-Welle): GESTE вҶ’ GESETZ.
// Eine wiederholt BEWГ„HRTE Geste (history: finalized, fitness вүҘ minFitness,
// вүҘ minRuns LГӨufe desselben Op-Kopfes) kristallisiert zu einer stehenden
// Regel; die EMOTIONS-SIGNATUR ihres Kontexts gebiert die Bedingung (E5).
AnazhRealm.GESTURE_CRYSTAL = Object.freeze({
    cooldownSec: 45, // hГ¶chstens alle 45 s ein Kristallisations-Versuch
    minFitness: 0.65, // nur wirklich bewГӨhrte LГӨufe zГӨhlen
    minRuns: 3, // Wiederholung macht das Gesetz (eine Einzeltat bleibt Geste)
    minEmotionIntensity: 0.25, // darunter trГӨgt der Kontext keine Signatur вҶ’ random_chance
});
AnazhRealm.WORLD_RULES = Object.freeze({
    cap: 64,
    budgetPerFrame: 4,
    defaultEverySec: 2,
    minEverySec: 0.5,
    // Phase C вҖ” Komposition
    composeRuleProb: 0.35, // Anteil der Nexus-Evolutionen, die eine REGEL sind (statt einer Geste)
    ruleEverySecMin: 1, // komponierte Regeln feuern alle 1вҖ“5 s
    ruleEverySecMax: 5,
    ruleTtlMin: 30, // Lebens-Fenster einer Nexus-Regel (30вҖ“90 s; Fitness erneuert sie)
    ruleTtlMax: 90,
    mutateSurvivorProb: 0.4, // P(eine neue Nexus-Regel ist ein mutierter Nachkomme eines Гңberlebenden)
    // Phase C вҖ” Fitness (per-Regel, attributierbar: Kosten + Erfolg + Engagement)
    costBudgetMs: 4, // ein Regel-Effekt sollte < ~4 ms kosten (sonst Cost-Penalty)
    renewFitness: 0.5, // ab dieser Fitness wird eine Nexus-Regel am ttl-Ende erneuert
    // V17.41 вҖ” der Gesetzes-Faden: ein Gesetz, das innerhalb dieser Frist gefeuert
    // hat, gilt als вҖһfeuert gerade" (der Live-Puls in der Gesetze-Console). > als
    // der grГ¶Гҹte everySec (ruleEverySecMax 5) вҶ’ ein aktiv feuerndes Gesetz pulst
    // kontinuierlich; verstummt es, fГӨllt es nach dieser Frist auf вҖһaktiv В· NГ—".
    threadRecentSec: 6,
});

// V17.42 вҖ” DIE LEBENDIGE WERTUNG (das dritte Verb des Feldes: lesen вҶ’ schreiben вҶ’
// WERTEN). Die Stellschrauben der gleitenden Baseline + des Wohl-MaГҹes. Die EINE
// bewГӨhrte Gleichung (EMA-Tiefpass + Differenz `Оҙ = x вҲ’ baseline`, auf die RL/Dopamin-
// RPE/Prospect-Theory unabhГӨngig kamen) braucht nur Zeitkonstanten вҖ” der GESAMTE neue
// вҖһHardcode". Phase 1 (V17.42) baut NUR das MaГҹ + die Baseline (Mess-Schicht); die
// Konsumenten вҖ” Regel-Fitness (Phase 2) + Emotion-Appraisal (Phase 3) вҖ” kommen danach.
// Reaktive Schicht (nicht persistiert, kein Worker-Mirror, V9.67). docs/lebendige-wertung-plan.md.
//   cell        вҖ” Zell-GrГ¶Гҹe der Baseline-Map (= LIFE_FIELD.cell, 16 m)
//   fieldTau    вҖ” Zeitkonstante der ORTS-Baseline (s); ~120 s вҶ’ ein Ort re-normalisiert langsam
//   playerTau   вҖ” Zeitkonstante der SPIELER-Baseline (s); ~30 s вҶ’ GewГ¶hnung in einer Sitzung
//   pruneEverySec / pruneAgeSec вҖ” die Baseline-Map bounded halten (lange nicht beobachtet вҶ’ weg)
AnazhRealm.WERTUNG = Object.freeze({
    cell: 16,
    fieldTau: 120,
    playerTau: 30,
    pruneEverySec: 5,
    pruneAgeSec: 180,
    // V17.43 Phase 2 вҖ” die EMA-Rate, mit der rule.value den per-Feuern gemessenen
    // Reward (lokaler struktureller Оҙ) integriert. Eine Regel braucht mehrere Feuern,
    // um sich als Heiler/SchГӨdling zu beweisen (kein Snap-Urteil). value вҲҲ [вҲ’1, +1].
    ruleValueBeta: 0.3,
    // V17.44 Phase 3 вҖ” der Appraisal-Kanal (Emotion = Vorhersagefehler des ERLEBENS,
    // Оҙ = Situation вҲ’ Spieler-Baseline). gain = wie stark ein Оҙ die Emotion bewegt (pro
    // Sekunde, sanft, ADDITIV zu V17.30/V17.21); deadzone = Totzone gegen Zappeln.
    appraisalGain: 0.4,
    appraisalDeadzone: 0.05,
    // V17.50 Phase 4 вҖ” DIE KLAMMER: rule.value (lokaler struktureller Оҙ) und Оҙ_spieler
    // (der ROHE Situations-Оҙ, Г¶kologisch) sind dasselbe Vorhersagefehler-Signal. Eine
    // Regel, die NAH am Spieler feuert UND mit positivem Оҙ_spieler zusammenfГӨllt, bekommt
    // Bonus-Credit вҶ’ die Welt lernt spieler-zentrisch (sie blГјht, WO der Spieler ist).
    appraisalEmaTau: 8, // s вҖ” die kurze EMA des Spieler-Оҙ (die jГјngste Erlebnis-Tendenz)
    phase4Radius: 40, // m вҖ” nur Regeln innerhalb dieses Radius vom Spieler bekommen den Bonus
    phase4Weight: 0.5, // wie stark ein positiver Оҙ_spieler den Regel-Reward hebt (Г— NГӨhe)
});

AnazhRealm.STAT_FROM_TAGS = Object.freeze({
    hpMax: (t) => 50 + (t.dichte || 0) * 60 + (t.hГӨrte || 0) * 30,
    damage: (t) => 5 + (t.hГӨrte || 0) * 15 + (t.dichte || 0) * 5,
    // V17.51 Kampf-Bogen Phase A (kampf-plan.md В§4-A) вҖ” die Kombat-Stats EMERGIEREN
    // aus der Substanz, GENAU im bestehenden Muster (Base + TagВ·Gewicht; die Tabelle
    // IST die Regel). knockback вҲқ dichte (Masse stГ¶Гҹt zurГјck) + hГӨrte (schwach);
    // attackSpeed вҲқ (1вҲ’dichte) (leicht = schnell) + magieleitung (flink) вҶ’ eine schwere
    // dichte Keule schlГӨgt langsam-wuchtig, eine leichte harte Klinge schnell. Der
    // GAMEPLAY-Konsum (Knockback-Impuls + Angriffs-Cooldown) folgt in Phase C/D; hier
    // wird das tag-emergente Profil definiert + sichtbar gemacht (renderPlayerStatsUI).
    knockback: (t) => 1 + (t.dichte || 0) * 9 + (t.hГӨrte || 0) * 2,
    attackSpeed: (t) => 0.8 + (1 - (t.dichte || 0)) * 0.7 + (t.magieleitung || 0) * 0.3,
    // SchГ¶pfer-Feedback 13.05.2026 (Welle 6.D Polish): вҖһMensch extrem
    // langsam, evt. Basegeschwindigkeit fГјr alle etwas hГ¶her". Base 4вҶ’6,
    // Multiplikator (1-dichte) 4вҶ’5, magieleitung 1вҶ’1.5. Mensch springt
    // von 6.1 auf ~8.75; PhГ¶nix 9.4 auf 11.2; Drache 5.0 auf 7.4. Sprint
    // = 2Г— Walk wirkt damit deutlicher.
    speed: (t) => 7 + (1 - (t.dichte || 0)) * 5 + (t.magieleitung || 0) * 1.5,
    jumpPower: (t) => 8 + (1 - (t.dichte || 0)) * 5 + (t.magieleitung || 0) * 2,
    staminaMax: (t) => 100 + (1 - (t.dichte || 0)) * 60 + (t.wГӨrmeleitung || 0) * 40,
    // V18.196 вҖ” MANA-SYMMETRIE: die zweite Ausdauer-Achse, treibt aus
    // magieleitung statt aus (1-dichte). Symmetrisch zu staminaMax: base 50
    // + magieleitungВ·100 (max ~150 bei voll magieleitung) + resoniertВ·30
    // (SekundГӨr-Boost вҖ” eine resonante Substanz hat eine offenere Mana-
    // Bandbreite). Mensch (magieleitung 0, resoniert 0) вҶ’ 50 Default; Drache
    // (magieleitung ~0.3) вҶ’ ~80; PhГ¶nix (magieleitung ~0.6 + resoniert ~0.3)
    // вҶ’ ~119. Eine Welt-Stimme, die schlief, wird zur zweiten Lebens-Achse.
    manaMax: (t) => 50 + (t.magieleitung || 0) * 100 + (t.resoniert || 0) * 30,
    precision: (t) => 0.5 + (t.magieleitung || 0) * 0.3 + (t.zГӨhigkeit || 0) * 0.2,
    magicResist: (t) => (t.magieleitung || 0) * 0.4 + (t.resoniert || 0) * 0.3,
    heatResist: (t) => (t.wГӨrmeleitung || 0) * 0.5 - (t.brennbar || 0) * 0.3,
    // V17.51 Kampf-Bogen Phase A вҖ” defense (PHYSISCH) вҲқ dichte + hГӨrte (dichte, harte
    // RГјstung blockt); ergГӨnzt magicResist/heatResist (elementar) zum vollstГӨndigen
    // Defense-Trio. Base-los wie die elementaren Resists (ein weiches Wesen blockt ~0).
    // Konsum als flache Schadens-Reduktion (dealt = max(1, amount вҲ’ defense)) in Phase C.
    defense: (t) => (t.dichte || 0) * 8 + (t.hГӨrte || 0) * 6,
});

