AnazhRealm.SCATTER = Object.freeze({
    cellM: 3.4, // Plan В§3.5 вҖ” Baum-Zell-Raster (die Canopy-Schicht)
    regionM: 256, // eine Scatter-Region = 16 Voxel-Chunks (= Bake-Region V18.219)
    promoteM: 64, // < diesem Radius вҶ’ der Scatter-Baum wird ein ECHTER Bauplan (TouchвҶ’Real)
    innerM: 64, // innerhalb: keine Deko-Streu (der promovierte/reale Ring trГӨgt)
    outerM: 384, // ГӨusserer Rand der Deko-Streu (jenseits trГӨgt die Canopy-Shell)
    ringRegions: 1, // Вұ1 Region = 3Г—3 (768mВІ) aktiver Scatter-Ring
    perRegionCap: 1400, // (Legacy вҖ” die Baum-Schicht; die layers-Liste trГӨgt jetzt die Caps)
    densityFloor: 0.1, // lebendig-Boden fГјr jeden Baum-Scatter
    densityScale: 1.5, // Multiplikator auf die lebendig-getriebene Wahrscheinlichkeit
    slopeMax: 1.45, // SteilhГӨnge tragen weniger Scatter (Fels-Zone)
    maxRegionsPerFrame: 1, // bounded: max 1 Region/Frame generieren (Plan В§5)
    // V18.225 (DER ATEMBERAUBENDE WALD вҖ” Plan В§13 вҖһвүҘhunderte/Chunk + 5 Schichten"):
    // die MEHRSCHICHTIGE Dichte. Eine Baum-Schicht allein (3.4m-Zelle = ~161
    // Zellen/43.2m-Chunk) erreicht NIE вҖһhunderte" вҖ” der Plan verlangt die fГјnf
    // Vegetations-Strata, die ZUSAMMEN den dichten Boden ergeben: Canopy (BГӨume)
    // + Strauch (Hazel) + Kraut (Farn) + Bodenflora (Blume) + Streu (Totholz).
    // Drei Scatter-PГӨsse (Strauch+Kraut+Blume teilen den feineren under-Pass),
    // jeder mit eigenem Zell-Raster + Cap. Region = 256m вүҲ 35 Chunks (span 43.2m)
    // вҶ’ die Caps zielen auf ~180-220 Instanzen/Chunk gesamt = вҖһhunderte".
    layers: Object.freeze([
        // V18.233 (SUBSTANZ-REBALANCE, SchГ¶pfer-Befund вҖһBГӨume ragen kaum, FPS вҶ’ 0"):
        // WENIGE, GROSSE, varianz-reiche BГӨume (cap 1700вҶ’900, scaleVar 0.66вҶ’1.5 =
        // Scale 0.6-2.1 вҶ’ ragende Alte + junge) statt vieler sparse Stacheln. Die
        // Krone ist 1.7Г— lusher (FPS-neutral, s. _buildTreeFoliageCardGeometry).
        // V18.267 (PROVISORISCHE ENTLASTUNG, SchГ¶pfer вҖһich sehe hunderte BГӨume aber
        // sonst kaum was вҖ” vorerst provisorisch entlasten"): cap 900вҶ’300 (offenes
        // Waldland statt dichter Forst вҶ’ Terrain/Fels/Blumen werden sichtbar, FPS
        // entlastet). REVERSIBEL вҖ” der echte Dichte-Regler ist der kommende
        // Perf-Regelkreis-Render-Hebel; dies ist die Sofort-Linderung.
        Object.freeze({
            name: "tree",
            cellM: 3.4,
            // V18.296 (SchГ¶pfer-Anordnung, 20+ Versionen ГјberfГӨllig: вҖһsehe immernoch
            // hunderte BГӨume вҖҰ wir gehen runter"): cap 300вҶ’90 (~2.6 BГӨume/Chunk =
            // offenes Waldland, freie Sicht auf Terrain/Fels/Substanz). REVERSIBEL.
            cap: 55, // V18.303 90вҶ’55: das Laub war 90 % der GPU-Last (gemessen) + SchГ¶pfer вҖһzu viele BГӨume, sonst kaum was"
            floor: 0.1,
            scaleBase: 0.6,
            scaleVar: 1.5,
            slopeMax: 1.45,
            kind: "tree",
            promotable: true,
        }),
        // Understory: Strauch+Kraut+Bodenflora. WAR der Haupt-Dichte-TrГӨger (4200)
        // = der FPS-Killer + visuelle Verstopfung (kleines GestrГјpp verdeckte die
        // BГӨume). V18.233: 4200вҶ’800; V18.267: 800вҶ’250 (mit den BГӨumen entlastet вҖ”
        // weniger GestrГјpp, mehr Sicht auf die Substanz; bleibt < treeCap, damit
        // die BГӨume die prominente Substanz bleiben, nicht das GestrГјpp). REVERSIBEL.
        Object.freeze({
            name: "under",
            cellM: 2.4,
            cap: 40, // V18.303 70вҶ’40 (das Laub = 90 % der GPU-Last); V18.296 250вҶ’70
            floor: 0.06,
            scaleBase: 0.8,
            scaleVar: 0.5,
            slopeMax: 1.0,
            kind: "under",
            promotable: false,
        }),
        // Streu: Totholz am Boden (2.8m-Zelle, sparse). V18.267: 250вҶ’150 (mit-
        // entlastet вҖ” Totholz war der 2.-grГ¶sste gewachsene Render-Posten).
        Object.freeze({
            name: "litter",
            cellM: 2.8,
            cap: 22, // V18.303 40вҶ’22 (das Laub = 90 % der GPU-Last); V18.296 150вҶ’40
            floor: 0.04,
            scaleBase: 0.8,
            scaleVar: 0.4,
            slopeMax: 1.25,
            kind: "litter",
            promotable: false,
        }),
        // V18.227 (О©-OPSIS SГӨule II О©-O5) вҖ” FELS: Kiesel + Felsbrocken, wo der Fels
        // durchbricht (rockExposure aus slope+trocken+kahl, das Spiegelbild der
        // SГӨule-I-Geologie). Eigener densityScale + hoher slopeMax (Fels mag steil),
        // grosse Skalen-Varianz (Kiesel bis Brocken). Deko, nicht promotable.
        Object.freeze({
            name: "rock",
            cellM: 2.6,
            cap: 110, // V18.303 350вҶ’110: 350 Kiesel/Region = absurd viele Instanzen fГјr winzigen Look-Wert (der grГ¶Гҹte Instanz-Posten nach den BГӨumen)
            floor: 0.02,
            scaleBase: 0.6,
            scaleVar: 1.0,
            slopeMax: 1.6,
            densityScale: 1.3,
            kind: "rock",
            promotable: false,
        }),
    ]),
});

// V18.212 вҖ” О©-C CANOPY-SHELL (DER LEBENDIGE GIGANT В§9): die ferne Wald-
// OberflГӨche, die individuelle BГӨume in der Distanz cullt und durch eine
// geschlossene grГјne FlГӨche ersetzt. Plan-В§9-Formel:
//   lift = smoothstep(0.18, 0.5, coverage) В· (coverage В· 7 + 11)
//   canopyTop = terrain + lift + crown-bumps
// Coverage in unserer Architektur: `worldFieldAt.lebendig` Г— Clump-Faktor
// (V18.102-Wald-Maske О»~170m). Konsistent mit dem Scatter вҖ” derselbe Term
// treibt Tree-Spawn-Probability + Canopy-Lift. Frozen Konstanten browser-
// justierbar wenn der SchГ¶pfer Look-Feinheiten anpasst.
AnazhRealm.CANOPY_SHELL = Object.freeze({
    // Gitter-AuflГ¶sung: 96Г—96 = 9216 Vertices. ~21m Vertex-Abstand bei 2km
    // Region вҖ” fein genug fГјr sichtbare Strukturen, grob genug fГјr FPS.
    gridSize: 96,
    // Welt-Abdeckung in m. Вұ1024m ist der Worldgen-Bereich (wo `lebendig`
    // definiert ist); 2048m = 2km Г— 2km.
    regionM: 2048,
    // Distanz-Dither: Canopy fadet von distNear (m) bis distFar (m) ein.
    // Vor distNear: unsichtbar (EinzelbГӨume tragen die Wahrheit). Ab distFar:
    // voll sichtbar als ferne Wald-OberflГӨche.
    distNear: 180,
    distFar: 320,
    // Maximale Deckkraft am Horizont вҖ” < 1.0 damit AtmosphГӨre durchscheint.
    maxOpacity: 0.85,
    // Lift-Skala: 1.0 = Plan-Formel direkt. Browser-justierbar wenn die
    // BГӨume вҖһzu hoch" Гјber dem Terrain liegen.
    liftScale: 0.85,
});

// V18.235 (wahreranblick В§3 вҖ” DIE LUSHE KRONE, вҖһdie Samen werden zu MammutbГӨumen"):
// die Krone als VOLUMEN. Vorher EINE card{cross} pro Foliage-Anchor (~21 Karten in
// einem 22 m-Baum вҶ’ ein dГјnner Stachel, der GEMESSENE 10%-Befund). Jetzt ein
// CLUSTER aus K Karten pro Anchor, jittered im Kronen-Volumen (ein Teil zur Mitte
// gezogen) вҶ’ die geschlossene, lushe Krone (hunderte Karten). Eine card{cross} ist
// billig (8 Verts) вҶ’ die volle Krone ist FPS-tragbar bei LOD0 (nah); LOD1/2 dГјnnen
// per cardsPerAnchor stark aus (der LOD-Pfad trГӨgt die Performance, kein Cap-Schnitt).
// Browser-justierbar (state.atmosphere kann die Werte Гјberschreiben вҖ” _foliageDensity()).
AnazhRealm.FOLIAGE_DENSITY = Object.freeze({
    // V18.245 (wahreranblick В§8.5 вҖ” gegen die echten Referenz-BГӨume): die echte Eiche/Tanne
    // hat eine DICHTE, geschlossene Krone; meine war locker/lГ¶chrig. Mehr Karten + engerer
    // Cluster + mehr Volumen-FГјllung вҶ’ die geschlossene Dome/Kegel-Masse. LOD0 only (LOD1/2
    // bleiben dГјnn вҶ’ die FPS-Last trГӨgt der LOD-Pfad, kein Cap-Schnitt).
    // V18.248 (wahreranblick В§8.5 вҖ” DIE LAAS-KARTEN-ZAHL, SchГ¶pfer вҖһbГӨume sehen noch sehr
    // chaotisch aus"): die Wurzel des Chaos вҖ” seit der Atlas (V18.247) eine Karte zu einem
    // GEBACKENEN ~16-Blatt-BГјschel macht, sind 16 Karten/Anker = 16Г—16 BlГӨtter pro Anker in
    // einer Jitter-Wolke = Brei. LAAS nutzt 1-2 Karten/Anker (das BГјschel STECKT im Atlas).
    // Jetzt 3 groГҹe, RUHIGE BГјschel-Karten/Anker вҶ’ distinkte, geordnete Laub-BГјschel an den
    // Ast-Spitzen statt Chaos. GrГ¶Гҹere Karten (s.u. cardW/cardH) halten die Krone voll.
    // V18.249 (SchГ¶pfer вҖһblГӨtter unverhГӨltnismГӨssig gross") вҖ” kleinere BГјschel-Karten (s.u.
    // cardW), dafГјr ein paar mehr/Anker вҶ’ proportionierte BlГӨtter UND volle Krone. Das
    // RADIALE Atlas-BГјschel (feine BlГӨtter) hГӨlt es ruhig trotz mehr Karten.
    cardsPerAnchor: [5, 2, 1], // pro LOD0/1/2 вҖ” moderate Zahl mittelgroГҹer BГјschel
    jitterFrac: 0.5, // Cluster-Spreizung (BГјschel Гјberlappen sanft вҶ’ volle Krone)
    sizeVar: 0.3, // Вұ30% (organisch)
    innerFill: 0.2, // etwas FГјllung, das Ast-GerГјst bleibt aber sichtbar
});

