    minStrikeProgress: 0.06, // selbst die Faust an Granit macht WINZIGEN Fortschritt (nie 0 = HГӨnger)
    maxStrikeProgress: 1.0, // ein Гјberlegenes Werkzeug ein-hiebt Weiches
