// W7 Phase 2 вҖ” Welt-Snapshot Гјber das Mesh. Ein Joiner/Guest holt die
// Welt des Hosts in StГјcken Гјber den RTCDataChannel statt in einem WS-
// Frame (das hatte ein 1-MiB-Limit + war ein Host-Bottleneck). 16 KiB pro
// StГјck ist die interop-sichere DataChannel-NachrichtengrГ¶Гҹe; Backpressure
// Гјber channel.bufferedAmount fГӨngt grosse Welten ab.
AnazhRealm.P2P_WORLD_CHUNK_SIZE = 16384;
// V9.44-d вҖ” die Backpressure-Schwelle fГјr den RTCDataChannel-Versand.
// Steigt `channel.bufferedAmount` Гјber diesen Wert, pausiert der Sender.
// Als 16 Г— P2P_WORLD_CHUNK_SIZE definiert (= 262144) вҖ” die Beziehung
// вҖһ16 StГјcke dГјrfen im Puffer warten" sichtbar gemacht statt eines
// gestreuten Magic-Literals (vorher 262144 Г—2 hand-getippt).
AnazhRealm.P2P_BACKPRESSURE_BYTES = 16 * AnazhRealm.P2P_WORLD_CHUNK_SIZE;
// V9.44-d вҖ” Infrastruktur-Defaults, vorher als gestreute Literale.
// Ollama-Endpoint: der lokale Default-Server (8 Stellen vorher hand-
// getippt). P2P-WS-URL: die Default-Signaling-Server-Adresse (6 Stellen).
// Eine zentrale Stelle pro Wert вҖ” Drift-Schutz.
AnazhRealm.OLLAMA_DEFAULT_ENDPOINT = "http://localhost:11434";
AnazhRealm.P2P_DEFAULT_WS_URL = "ws://127.0.0.1:4313";
// W7 Phase 2 вҖ” Mindestabstand zwischen zwei world-pull-Antworten an
// denselben Peer. SchГјtzt vor pull-Spam (jeder Pull serialisiert + sendet
// die ganze Welt вҖ” ohne Limit ein DoS-Vektor).
AnazhRealm.P2P_PULL_COOLDOWN_MS = 5000;

// W16 Phase 1 вҖ” Mesh-Welt-Verteilung. Eine vendorte Welt reist peer-to-peer:
// ihr BГјndel wird in P2P_WORLD_CHUNK_SIZE-StГјcken Гјber den DataChannel
// Гјbertragen (Spiegel des W7-P2-world-pull). Mindestabstand zwischen zwei
// bundle-pull-Antworten an denselben Peer вҖ” ein BГјndel-Read + Versand ist
// teuer, ohne Limit ein DoS-Vektor.
AnazhRealm.P2P_BUNDLE_PULL_COOLDOWN_MS = 5000;
// W16-Politur вҖ” der weiche Pull-Timeout: hГӨngt ein Welt-BГјndel-Pull lГӨnger
// als das, gibt _p2pCheckBundlePullTimeout ihn frei (der Sender verschwand
// vermutlich mitten im Chunk-Strom). 30 s вҖ” grosszГјgig fГјr ein Text-Welt-
// BГјndel Гјber einen DataChannel.
AnazhRealm.P2P_BUNDLE_PULL_TIMEOUT_MS = 30000;

// W7 Phase 3 вҖ” LLM-Pool. Ein Peer mit aktivem LLM teilt seine вҖһStimme",
// ein schlГјsselloser Peer routet Chat-Anfragen Гјber ihn. Sicherheits-
// lastig (fremder Prompt Гјber meinen Key): Opt-in + Rate-Limit. Cooldown
// pro anfragendem Peer (eine LLM-Anfrage kostet Token + Zeit), Timeout
// fГјr den Anfrager (LLM-Calls sind langsam), Prompt-LГӨngen-Deckel.
AnazhRealm.P2P_VOICE_COOLDOWN_MS = 6000;
AnazhRealm.P2P_VOICE_TIMEOUT_MS = 30000;
AnazhRealm.P2P_VOICE_PROMPT_MAX = 2000;

