// ab: moveable, magnifying, focusing. KEINE Form-Whitelists, KEINE
// Tabelle вҖһBauplan-Name X ist Auto" вҖ” eine Welt-Lese-Funktion entscheidet
// aus Material Г— rГӨumlicher Verteilung was das Compound IST.
//
// SchГ¶pfer-Korrektur (16.05.2026): Form-Whitelists (cylinder/torus als
// вҖһRГӨder", cone/cylinder als вҖһAchsen") waren Hardcode-BrГјche im Vision-
// Pfad. Vision-rein: emergent aus Tag-Sprache + rГӨumlicher Topologie.
//
// Drei Starter-Affordances:
//   moveable    вҖ” bewegliches Compound: StГјtz-Konfiguration (вүҘ2 Parts
//                 in unterer bbox-HГӨlfte) + dichte (TrГӨgheit) +
//                 Antriebs-Tag (magieleitung oder stromleitung)
//   magnifying  вҖ” optisches Compound: transparent вүҘ Schwelle + Parts
//                 entlang einer Achse ausgerichtet (axialer Aufbau)
//   focusing    вҖ” brennfГӨhiges Compound: transparent + wГӨrmeleitung
//                 (reine Tag-Sprache, keine Form-Erwartung)
// ============================================================
AnazhRealm.AFFORDANCE_THRESHOLDS = Object.freeze({
    moveable: Object.freeze({
        minSupportParts: 2, // вүҘ2 Parts in unterer bbox-HГӨlfte
        midlineFactor: 0.5, // unten = unter bbox-Mitte (relativ!)
        supportSpreadMin: 0.35, // V17.11 вҖ” StГјtz-Parts spreizen вүҘ35 % der Breite
        //   (Trag-Basis: RГӨder/Beine quer) вҖ” eine schmale SГӨule (Baum-Stamm-
        //   Stapel, Spreizung ~0) ist KEIN Fahrzeug. Emergent, kein Form-Flag.
        dichteMin: 0.3, // Compound muss TrГӨgheit haben
        antriebTagMin: 0.3, // magieleitung ODER stromleitung
    }),
    magnifying: Object.freeze({
        transparentMin: 0.5, // Compound transparent-Tag
        axialAlignmentMin: 0.6, // вүҘ60 % der Parts auf einer Linie
        minAxialParts: 2, // mind. 2 Parts fГјr eine Achse
    }),
    focusing: Object.freeze({
        transparentMin: 0.5,
        wГӨrmeMin: 0.3,
    }),
    // W10 ext. вҖ” radiating: ein resonanz-strahlendes Compound. resoniert-Tag
    // Гјber Schwelle + radiale Spreizung (Parts NICHT auf einer Achse).
    // resoniertMin = WORLD_EFFECT_THRESHOLDS.resonance_strong (1.5) вҖ” dieselbe
    // Schwelle, ab der W4 V4 die Symphonie verdichtet; ein Stein-Dorf (resoniert
    // ~0.6) strahlt NICHT, erst eine genuin resonante Quarz-Form (~1.8).
    radiating: Object.freeze({
        minParts: 3, // ein Einzelteil hat keine Spreizung
        resoniertMin: 1.5, // das Compound schwingt STARK вҖ” es strahlt
        radialMax: 0.6, // axiale alignmentRatio UNTER 0.6 вҶ’ radial, kein Mast
    }),
    // W10 ext. вҖ” broadcasting: ein leitfГӨhiger, aufrechter Mast (Relais).
    // Axiale Ausrichtung entlang der y-Achse + LeitfГӨhigkeit. KomplementГӨr
    // zu radiating (radialMax 0.6 вҶ” alignMin 0.6 вҖ” derselbe Schwellwert
    // trennt radial von axial sauber).
    broadcasting: Object.freeze({
        minParts: 3, // ein Mast braucht mehrere Parts
        alignMin: 0.6, // вүҘ60 % der Parts auf der (vertikalen) Achse
        leitfaehigMin: 0.4, // stromleitung ODER magieleitung вҖ” es trГӨgt ein Signal
    }),
    // W10 ext. вҖ” balancing: ein breites, bodenlastiges, schweres Compound
    // (Fundament). Breite Basis + tiefer Schwerpunkt + genuin schwer.
    balancing: Object.freeze({
        minParts: 3,
        wideMin: 1.0, // horizontale Spannweite вүҘ vertikale (breiter als hoch)
        bottomHeavyMin: 0.6, // вүҘ60 % der Parts in der unteren bbox-HГӨlfte
        dichteMin: 1.5, // genuin schwer (= resonance_strong-Niveau, kein Gate-Tief)
    }),
    // W10 ext. вҖ” lifting: ein magie-geladenes, leichtes Compound (Auftriebs-
    // Feld). Stark magie-geladen + genuin leicht вҖ” das Komplement zu
    // balancing (dichteMax 1.0 вҶ” balancing.dichteMin 1.5).
    lifting: Object.freeze({
        minParts: 3,
        magieMin: 1.5, // stark magie-geladen вҖ” es trГӨgt die Hebe-Energie
        dichteMax: 1.0, // genuin leicht вҖ” Magie hebt kein Gewicht
    }),
});

// Welle 11 ext. вҖ” Substanz-Rolle. Schwellen fГјr die intrinsischen Rollen-
// Signale: body (Seele aus KГ¶rper-Symmetrie) + food (Nahrung aus lebendig+
// weich). Bewusst KEIN 11. Material-Tag (Heilige Lektion вҖ” die 10 Tags
// bleiben die eine Sprache); Nahrung emergiert aus den bestehenden Tags.
AnazhRealm.SUBSTANCE_ROLE_THRESHOLDS = Object.freeze({
    body: Object.freeze({
        minParts: 3, // ein KГ¶rper hat mehrere Teile
        symmetryMin: 0.78, // Anteil Parts mit Spiegel-Partner (bilateral)
        minLimbPairs: 1, // вүҘ1 echtes Off-Achsen-Spiegel-Paar (Glieder)
        offAxisMin: 0.18, // |x вҲ’ Zentrum| / spanX ab dem ein Part "Glied" ist
        mirrorTol: 0.35, // Spiegel-Such-Toleranz, relativ zur Compound-GrГ¶Гҹe
        verticalMin: 0.45, // Y-Spanne вүҘ 45 % der horizontalen вҖ” ein KГ¶rper
        // "steht"; ein flaches Dorf (HГјtten in der xz-Ebene) fГӨllt raus.
        // V18.181-merge-Оӣ Sub 3c вҖ” Оӣ.1 (clever-gauss V18.173): lebendige
        // Masse in der Mitte. livingMassMin = ОЈ(volВ·lebendig) muss > 0.02
        // sein (ein bisschen Fleisch/Laub/Blut); livingCenterMinY/MaxY
        // klemmt den Y-Schwerpunkt der lebendigen Masse relativ zur
        // POSITIONS-BBox auf [0.25, 0.80] вҖ” anatomisch-realistische Body
        // (Kopf+Rumpf+Arme oben, Beine unten) hat liveCenterY вүҲ 0.75
        // GEMESSEN (Test V17.84). Pilz mit Krone (yNorm > 0.80) und
        // Bodenflora (yNorm < 0.25) fallen weiterhin raus. Plan-Erstwurf
        // war [0.30, 0.70], bei der Synthese auf den Test gegen-vermessen
        // und gelockert вҖ” die Wand bleibt strukturell, nur ihr Bereich
        // ist groГҹzГјgiger (Plan В§14.3-Drift mitigiert).
        livingMassMin: 0.02,
        livingCenterMinY: 0.25,
        livingCenterMaxY: 0.8,
    }),
    food: Object.freeze({
        lebendigMin: 0.6, // klar lebendig (Fleisch, Laub, Frucht)
        hГӨrteMax: 0.5, // weich genug zum Essen
    }),
    // W12 вҖ” Tor-Signatur. Die begehbare GrГ¶Гҹe ist KEINE feste Zahl mehr вҖ”
    // _avatarPassageSize misst sie an der Ausdehnung des Reisenden (ein
    // Drache-Tor ist grГ¶Гҹer als ein Menschen-Tor). magieleitungMin: ein Tor
    // leitet Magie вҖ” ein Stein-/Eisen-Ring (magieleitung 0) bleibt darunter,
    // ein Quarz-Ring darГјber.
    portal: Object.freeze({
        magieleitungMin: 1.3,
    }),
});

// R1 (kampf-plan В§11.10) вҖ” die WERKSTATT-DOMГ„NE als RESONANZ-Signaturen (ein Produkt-Vektor, viele Leser).
// Jede DomГӨne ein Signatur-Vektor Гјber die Material-Tags (Gewichte dГјrfen NEGATIV sein вҖ” Invers-Achsen);
// _computeWorkshopDomain gibt das ARGMAX der Resonanz (`_blueprintResonance`), null unter dem Floor. An den
// 5 Built-in-WerkstГӨtten GEMESSEN (checkBandV1767 friert die Baseline ein): alchemy = ein durchsichtiges
// GefГӨГҹ (Quarz-Kolben transparent 2.85); mechanism = ein strom-leitender, wГӨrme-fГјhrender Apparat (Eisen-
// Spindel stromleitung 2.55, wГӨrme 2.1); soulwork = ein magie-leitender, resonierender Kanal (Quarz-Helix
// magie 2.55); forging = eine dichte, hitze-tragende Masse (Stein+Bronze+Glut dichte 2.64); textile = ein
// weicher, zГӨh-lebendiger Rahmen (Leder/Holz: niedrige hГӨrte, zГӨhigkeit+lebendig). Multi-Achsen = der ganze
// Vektor wird gelesen, nicht ein Tag. Der Floor trennt eine Werkstatt von einer bloГҹen Struktur.
AnazhRealm.WORKSHOP_DOMAIN_SIGNATURES = Object.freeze({
    alchemy: Object.freeze({ transparent: 1.0 }),
    mechanism: Object.freeze({ stromleitung: 1.0, wГӨrmeleitung: 0.2 }),
    soulwork: Object.freeze({ magieleitung: 1.0, resoniert: 0.2 }),
    forging: Object.freeze({ dichte: 1.0, wГӨrmeleitung: 0.3 }),
    textile: Object.freeze({ zГӨhigkeit: 1.0, lebendig: 1.0, hГӨrte: -1.0 }),
});
AnazhRealm.WORKSHOP_DOMAIN_RESONANCE_FLOOR = 2.0;

// R3 (kampf-plan В§11.10) вҖ” die ROLLE als RESONANZ des vollen Produkt-Vektors (Tags вҠ• rГӨumliche Achsen
// bodyShape/portalShape). computeBlueprintRole = die opChain-DomГӨne (Krafting-Intent, Vorrang) вҶ’ sonst das
// ARGMAX dieser Form-Signaturen (`_computeFormRole`). Die per-Rolle Hand-Flags (setBlueprintAs*) bleiben als
// optionaler SchГ¶pfer-OVERRIDE (roleManual). Die KONJUNKTIVE Geometrie (body/portal) lebt im Feature
// (bodyShape/portalShape = 0/1 aus den bestehenden PrГӨdikaten); die DISJUNKTIVE Entscheidung ist das argmax.
// DER HEAL (SchГ¶pfer 03.06.): вҖһarchitecture" ist eine POSITIVE Signatur (eine dichte, harte Struktur) вҖ” ein
// Tempel/Felsbogen (Stein: dichte 2.55, hГӨrte 1.95) resoniert damit STГ„RKER als mit soul, obwohl seine
// Geometrie body-fГ¶rmig ist вҶ’ er wird Bauwerk, nicht Seele; ein weicher fleisch-KГ¶rper resoniert soul stГӨrker.
// An den 12 Form-Fallback-Built-ins GEMESSEN (checkBandV1768 friert die Baseline ein). Floor вҶ’ architecture.
// V17.90 вҖ” fГјr die NORMALISIERTE Skala (A1: Material-Tags jetzt [0..1]) neu justiert + zwei Konjunktions-
// Heilungen: soul liest `livingBody` (KГ¶rper-Form UND lebendig вҖ” ein toter Panzer ist keine Seele), portal
// liest `portalShape` (die Ring-Form вҖ” ein magisches Kristall ohne Ring ist kein Tor). architecture bleibt
// der dichte-harte Default fГјr Welt-Strukturen (konservativ). An den Built-ins GEMESSEN (diag).
// M2 (meister-plan В§2 вҖ” die Rollen-Wahrheit, GEMESSEN diag-roles): + `vehicle` (die fehlende
// Rolle вҖ” der Wagen las вҖһBauwerk", das Holzross вҖһSeele"): rideable (sitz вҲ§ moveable) 1.8 schlГӨgt
// das Holzross-soul (1.587) klar (2.03) und den Wagen-architecture (0.83 вҶ’ 2.1). + `bulk` heilt
// die Trank-BГӨume (Befund 5, arithmetisch: Eiche bulk 0.83 вҶ’ consumable 0.667вҲ’0.67вүҲ0, architecture
// 0.307+0.25=0.56 вҶ’ Bauwerk; Trank + fleisch-Kugel: span < 2 m вҶ’ bulk 0, unberГјhrt).
// V18.258 (SchГ¶pfer-Gesetz вҖһeine Seele kann nicht aus Holz und Laub entstehen") вҖ” die
// UNBESEELTE lebendige Substanz: Pflanze + Erde LEBEN (lebendig 0.55вҖ“1.0), tragen aber
// keine SEELE (ein Baum ist kein Wesen). `_blueprintProductVector.livingBody` liest
// `lebendig` darum NUR Гјber die NICHT in dieser Menge stehenden Materialien вҶ’ ein Baum
// (rein holz+laub) fГӨllt emergent auf architecture, ein Wesen (fleisch/knochen/leder/
// federn/schuppen/glut/essenz) behГӨlt die Seele. Das GESETZ der Substanz trennt Wesen
// von Pflanze an der Wurzel (kein roleManual-Pflaster).
AnazhRealm.SOULLESS_SUBSTANCES = Object.freeze(new Set(["holz", "laub", "kraut", "erde"]));
AnazhRealm.FORM_ROLE_SIGNATURES = Object.freeze({
    soul: Object.freeze({ livingBody: 1.4, lebendig: 0.4 }),
    portal: Object.freeze({ portalShape: 1.6 }),
    vehicle: Object.freeze({ rideable: 1.8, spread: 0.3 }),
    // V18.162 (diag-nachbau GEMESSEN): ein NACHGEBAUTER Holz-Wagen ohne Sitz fiel
    // auf вҖһTrank" (holz.lebendig 0.7 trifft die Signatur). Die Gegen-Achse: ein
    // Trank hat KEINE Trag-Basis (spread вҖ” der Wagen 1.0, das Holzross 0.77, der
    // Trank/die Frucht 0) вҶ’ der tote Holz-Kasten wird Bauwerk, TrГӨnke unberГјhrt.
    consumable: Object.freeze({ lebendig: 1.5, hГӨrte: -0.5, bulk: -0.8, spread: -0.6 }),
    architecture: Object.freeze({ dichte: 1.0, hГӨrte: 0.6, bulk: 0.3 }),
});
// Der Floor auf die NORMALISIERTE Skala gesenkt (A1: Material-Tags jetzt [0..1] statt [0..3] вҶ’ die rohen
