    // ist KEINE Seele) + lebendig-Gradient + Symmetrie/Resonanz fГјr die Feinheit.
    soul: Object.freeze({ livingBody: 1.8, lebendig: 0.6, axialSymmetry: 0.4, bodyShape: 0.3, resoniert: 0.2 }),
