// die Emotion. Region-Skala (16-m-Zelle), kein per-Vertex. Browser-justierbar.
AnazhRealm.LIFE_FIELD = Object.freeze({
    cell: 16, // m вҖ” das HydrosphГӨre/Voxel-Raster (Region-Skala)
    decayPerSec: 0.008, // Halbwertszeit ~87 s (getendete Region lingert, verwaiste verblasst)
    pulseCenter: 0.25, // eine Geburt hebt die Zelle (sparse ~0.1 вҶ’ ~0.35, nicht mehr Minimum)
    pulseNeighbor: 0.1, // 3Г—3-Kernel-Rand (weiche rГӨumliche Ausbreitung, kein Block)
    max: 0.7, // SГӨttigung pro Zelle (frozen+overlay вҶ’ ~1; Wiederhol-Pulse sГӨttigen вҶ’ Nexus zieht weiter)
    epsilon: 0.004, // darunter wird eine Zelle gepruned (die Map bleibt bounded)
    pruneEverySec: 5, // Prune-Rate (piggyback auf updatePlayerEmotions)
    // V17.29 вҖ” der Kreatur-Trickle: Leben sustainiert sich, wo es wohnt. NUR
    // Nexus/Spieler-getragene Kreaturen (tendsLife) trГӨufeln вҖ” die ambiente
    // Fauna ist die FOLGE des Feldes (kein Runaway, V17.27-Disziplin). Sanft +
    // rate-limitiert; Kreaturen wandern вҶ’ ein zarter Lebens-Pfad, der die
    // getendete Region erhГӨlt (nicht ein Einzel-Puls, der verblasst).
    trickle: 0.05, // pro Trickle-Deposit (klein вҖ” ein Garten wird gepflegt, nicht geflutet)
    trickleEverySec: 3, // jede tendende Kreatur trГӨufelt hГ¶chstens alle 3 s
});

// V17.32 вҖ” die rГӨumlich-dynamische Emotion: das emotionale GEDГ„CHTNIS der Welt.
// Wie das Leben-Overlay, aber pro 16-m-Zelle ein 6-Achsen-Emotions-Abdruck. Der
// Moment des FГјhlens (`_feelAction`) MARKIERT den Ort; `auraAt` blendet den
// lokalen Abdruck ГңBER die globale Stimmung вҶ’ die Welt erinnert sich, wo der
// Spieler fГјhlte, und fГӨrbt diesen Ort (der V17.31-Welt-Tint liest `auraAt.
// emotion` вҶ’ wird damit rГӨumlich FГңR UMSONST = der Konsument, kein Passagier).
// Das ist die SCHREIB-Seite der emotion-Achse (heilt В§3.3 fГјr Emotion). Reaktive
// Schicht (wie Leben/Wetter) вҶ’ nicht persistiert, kein Worker-Mirror. Justierbar.
// Die sechs Emotions-Achsen вҖ” die EINE Liste (Hylomorphismus-Stil), genutzt vom
// rГӨumlichen Emotions-Blend (auraAt) + den Reset-Pfaden.
AnazhRealm.EMOTION_AXES = Object.freeze(["joy", "awe", "sorrow", "hope", "peace", "chaos"]);

// === Der emotionale Kern W1 вҖ” das dimensionale Substrat (docs/emotion-kern-plan.md) ===
// Unter den sechs diskreten GefГјhlen liegt ein KONTINUIERLICHER Raum: jeder Affekt
// ist ein PUNKT in Valenz Г— Erregung (Russell-Circumplex, Mehrabian-PAD). Diese
// Geometrie macht aus вҖһ6 unabhГӨngigen Schiebern" EINEN kohГӨrenten Zustand:
//   - der READOUT (`_emotionState`) liest den Valenz/Erregung-Schwerpunkt + die
//     INTENSITГ„T (Abstand vom Neutralen, 6-dim) вҶ’ bittersГјГҹ (joy+sorrow) hat
//     Valenz~0 ABER hohe IntensitГӨt (die FUSION, die das additive Modell verfehlt);
//   - die KOHГ„RENZ (in updatePlayerEmotions) lГӨsst gegensГӨtzliche Achsen (negativer
//     Dot in DIESER Geometrie) sich mild dГӨmpfen вҶ’ der Zustand wird ein Punkt, kein
//     inkohГӨrentes вҖһ6 Maxima zugleich". Die DГӨmpfung EMERGIERT aus der Geometrie
//     (kein Sonderfall-Paar-Hardcode) вҖ” der Hylomorphismus der Emotionen, eine Ebene
//     hГ¶her. Werte aus dem Circumplex (joy/awe/hope/peace +Valenz, sorrow/chaos
//     вҲ’Valenz; awe ambivalent вҶ’ ~0, hГ¶chste Erregung/вҖһWeite"). Browser-justierbar.
AnazhRealm.EMOTION_GEOMETRY = Object.freeze({
    joy: { valenz: 0.9, erregung: 0.5 }, // hohe Valenz, gehobene Erregung
    awe: { valenz: 0.1, erregung: 0.9 }, // ambivalent (Furcht + Wunder), hГ¶chste Erregung/Weite
    sorrow: { valenz: -0.9, erregung: -0.4 }, // tiefe Valenz, niedrige Erregung
    hope: { valenz: 0.7, erregung: 0.2 }, // positiv, sanfte zukunfts-Erregung
    peace: { valenz: 0.6, erregung: -0.7 }, // positiv, ruhig (niedrigste Erregung)
    chaos: { valenz: -0.7, erregung: 0.7 }, // negativ, hohe Erregung (das Gegenteil von Frieden)
});

