AnazhRealm.EMOTION_DECAY = Object.freeze({
    joy: 1.0, // mittel вҖ” Freude verklingt normal
    awe: 1.4, // Wunder/Гңberraschung verfliegt etwas schneller
    sorrow: 0.55, // Trauer BLEIBT (zerfГӨllt langsam вҶ’ ~1.8Г— lГӨnger)
    hope: 0.9, // Hoffnung lingert leicht
    peace: 0.6, // Zufriedenheit/Frieden hГӨlt an
    chaos: 2.2, // Furcht/Unruhe verfliegt SCHNELL (akut, kurz)
});
