AnazhRealm.EMOTION_TEND = Object.freeze({
    threshold: -0.35, // moodValence darunter (anhaltend trГјb) вҶ’ die KI trГ¶stet
    amount: 0.12, // der Hoffnungs-Schub der trГ¶stenden Geste
});

// === Der emotionale Kern W5 вҖ” das ABENTEUER GRADUIERT (docs/emotion-kern-plan.md) ===
