// V10.0-c вҖ” Three.js ist seit V10.0-b ein ESM-Modul, das via Bootstrap-
// Module-Script geladen wird. Dieser classic-defer-Script (`anazhRealm.js`)
// und das Bootstrap-Module sind beide deferred + sollten in document order
// laufen (WHATWG-Spec), aber das Module-Loading eines 238-File-Addon-
// Graphen (V10.0-c) kann den Bootstrap lГӨnger ausfГјhren lassen als unser
// defer-Script. Plus: AnazhRealm-Constructor nutzt schon `new THREE.Vector3()`
// im Top-Level вҖ” wir MГңSSEN auf `window.THREE` warten, BEVOR wir den
// Constructor rufen. Defensiver Polling-Wait alle 10 ms.
function _bootAnazhRealm() {
    if (typeof window !== "undefined" && typeof window.THREE === "undefined") {
        setTimeout(_bootAnazhRealm, 10);
        return;
    }
    const anazhRealm = new AnazhRealm();
    // Globale Referenz fГјr DevTools-Debug und automatisierten Playtest.
    if (typeof window !== "undefined") {
        window.anazhRealm = anazhRealm;
        // [PERF/TEST] Headless-Skin-Res-Cap-Seed: setzt der Playtest vor dem Laden
        // `window.__anazhHeadlessSkinResCap` (via evaluateOnNewDocument), greift der
        // Cap schon beim ALLERERSTEN Avatar-Build in init() (der ~270-Teil-Isosurface
        // baut sonst ~19 s). Produktion setzt das Flag nie вҶ’ 0 вҶ’ kein Effekt.
        if (window.__anazhHeadlessSkinResCap) AnazhRealm.__HEADLESS_SKIN_RES_CAP = window.__anazhHeadlessSkinResCap | 0;
    }
    anazhRealm.init();
}
_bootAnazhRealm();
